UINT64 AudioCyclesSinceLastQuery;   UINT64 TotalCyclesSinceLastQuery;   UINT32 MinimumCyclesPerQuantum;   UINT32 MaximumCyclesPerQuantum;   UINT32 MemoryUsageInBytes;
UINT32 CurrentLatencyInSamples;
UINT32 GlitchesSinceEngineStarted;
UINT32 ActiveSourceVoiceCount;   UINT32 TotalSourceVoiceCount;   UINT32 ActiveSubmixVoiceCount;   UINT32 ActiveResamplerCount;   UINT32 ActiveMatrixMixCount;   UINT32 ActiveXmaSourceVoices;
UINT32 ActiveXmaStreams;} XAUDIO2_PERFORMANCE_DATA;

typedef struct XAUDIO2FX_VOLUMEMETER_LEVELS {
float  *pPeakLevels;   float  *pRMSLevels;   UINT32 ChannelCount;
} XAUDIO2FX_VOLUMEMETER_LEVELS;
成员 pPeakLevels
在处理传递期间，将使用每个通道的最大绝对级别填充的数组。 数组必须至少为 ChannelCount
× size (float) 字节。 如果 pRMSLevels 不为 NULL，pPeakLevels 可能为 NULL。 pRMSLevels
在处理阶段，将使用每个通道的均方根级别填充的数组。 数组必须至少为 ChannelCount × size
(float) 字节。 如果 pPeakLevels 不为 NULL，pRMSLevels 可能为 NULL。 ChannelCount
正在处理的通道数。

